/**
 * Minimap Component (F025)
 *
 * A bird's eye view minimap showing the entire canvas at small scale.
 * Features:
 * - Shows simplified task density (heatmap-like visualization)
 * - Displays viewport rectangle indicating current visible area
 * - Click/drag on minimap to navigate
 * - Toggle visibility
 *
 * Positioned in the bottom-right corner of the canvas.
 */

import { useCallback, useMemo, useRef, useState, useEffect } from 'react';
import { Card, Icon } from '@blueprintjs/core';
import type { TaskRender } from '../data/types';
import { DEFAULT_VIEW_CONFIG } from '../data/types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Minimap dimensions
const MINIMAP_WIDTH = 200;
const MINIMAP_HEIGHT = 80;
const MINIMAP_PADDING = 4;

// Colors
const MINIMAP_BG = '#e8e8e8';
const VIEWPORT_RECT_COLOR = 'rgba(59, 130, 246, 0.3)'; // blue-500 with opacity
const VIEWPORT_RECT_BORDER = '#3b82f6'; // blue-500
const TASK_COLOR_LOW = '#fef3c7'; // amber-100
const TASK_COLOR_HIGH = '#dc2626'; // red-600

interface MinimapProps {
  /** Total number of trains */
  trainCount: number;
  /** Total number of days in the timeline */
  totalDays: number;
  /** Tasks for rendering density visualization */
  tasks: TaskRender[];
  /** Current camera X position (world coordinates) */
  cameraX: number;
  /** Current camera Y position (world coordinates) */
  cameraY: number;
  /** Current zoom level */
  zoom: number;
  /** Canvas width in pixels */
  canvasWidth: number;
  /** Canvas height in pixels */
  canvasHeight: number;
  /** Whether minimap is visible */
  visible: boolean;
  /** Callback when user clicks/drags on minimap to navigate */
  onNavigate: (worldX: number, worldY: number) => void;
  /** Callback to toggle visibility */
  onToggle: () => void;
}

/**
 * Convert world coordinates to minimap coordinates
 */
function worldToMinimap(
  worldX: number,
  worldY: number,
  worldWidth: number,
  worldHeight: number
): { x: number; y: number } {
  const x = (worldX / worldWidth) * MINIMAP_WIDTH;
  // Y is negative in world (trains go down), convert to positive for minimap
  const y = (-worldY / worldHeight) * MINIMAP_HEIGHT;
  return { x, y };
}

/**
 * Convert minimap coordinates to world coordinates
 */
function minimapToWorld(
  minimapX: number,
  minimapY: number,
  worldWidth: number,
  worldHeight: number
): { worldX: number; worldY: number } {
  const worldX = (minimapX / MINIMAP_WIDTH) * worldWidth;
  // Convert positive minimap Y to negative world Y
  const worldY = -(minimapY / MINIMAP_HEIGHT) * worldHeight;
  return { worldX, worldY };
}

/**
 * Generate heatmap data for minimap visualization
 * Groups tasks into grid cells and counts density
 */
function generateHeatmapData(
  tasks: TaskRender[],
  totalDays: number,
  trainCount: number,
  gridCols: number,
  gridRows: number
): number[][] {
  // Initialize grid with zeros
  const grid: number[][] = Array(gridRows)
    .fill(null)
    .map(() => Array(gridCols).fill(0));

  const daysPerCell = totalDays / gridCols;
  const trainsPerCell = trainCount / gridRows;

  // Count tasks in each cell
  for (const task of tasks) {
    const col = Math.floor(task.startDay / daysPerCell);
    const row = Math.floor(task.trainIndex / trainsPerCell);

    // Clamp to grid bounds
    const clampedCol = Math.min(gridCols - 1, Math.max(0, col));
    const clampedRow = Math.min(gridRows - 1, Math.max(0, row));

    grid[clampedRow][clampedCol]++;
  }

  return grid;
}

/**
 * Interpolate between two colors based on value (0-1)
 */
function interpolateColor(value: number): string {
  // Clamp value to 0-1
  const t = Math.max(0, Math.min(1, value));

  // Parse colors
  const lowR = 254, lowG = 243, lowB = 199; // amber-100
  const highR = 220, highG = 38, highB = 38; // red-600

  // Interpolate
  const r = Math.round(lowR + (highR - lowR) * t);
  const g = Math.round(lowG + (highG - lowG) * t);
  const b = Math.round(lowB + (highB - lowB) * t);

  return `rgb(${r}, ${g}, ${b})`;
}

export function Minimap({
  trainCount,
  totalDays,
  tasks,
  cameraX,
  cameraY,
  zoom,
  canvasWidth,
  canvasHeight,
  visible,
  onNavigate,
  onToggle,
}: MinimapProps) {
  const minimapRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Calculate world dimensions
  const worldWidth = totalDays * pxPerDay;
  const worldHeight = trainCount * pxPerTrain;

  // Generate heatmap data (coarse grid for performance)
  const gridCols = 40; // Horizontal cells
  const gridRows = 10; // Vertical cells
  const heatmapData = useMemo(
    () => generateHeatmapData(tasks, totalDays, trainCount, gridCols, gridRows),
    [tasks, totalDays, trainCount, gridCols, gridRows]
  );

  // Find max value for normalization
  const maxDensity = useMemo(() => {
    let max = 0;
    for (const row of heatmapData) {
      for (const val of row) {
        if (val > max) max = val;
      }
    }
    return max || 1; // Avoid division by zero
  }, [heatmapData]);

  // Calculate viewport rectangle in minimap coordinates
  const viewportRect = useMemo(() => {
    // Viewport dimensions in world coordinates
    const viewWidth = canvasWidth / zoom;
    const viewHeight = canvasHeight / zoom;

    // Viewport corners in world coordinates
    const viewLeft = cameraX - viewWidth / 2;
    const viewRight = cameraX + viewWidth / 2;
    const viewTop = cameraY + viewHeight / 2; // Y+ is up in world
    const viewBottom = cameraY - viewHeight / 2;

    // Convert to minimap coordinates
    const left = worldToMinimap(viewLeft, 0, worldWidth, worldHeight);
    const right = worldToMinimap(viewRight, 0, worldWidth, worldHeight);
    const top = worldToMinimap(0, viewTop, worldWidth, worldHeight);
    const bottom = worldToMinimap(0, viewBottom, worldWidth, worldHeight);

    // Calculate rectangle
    const x = Math.max(0, left.x);
    const y = Math.max(0, top.y);
    const width = Math.min(MINIMAP_WIDTH - x, right.x - left.x);
    const height = Math.min(MINIMAP_HEIGHT - y, bottom.y - top.y);

    return { x, y, width: Math.max(4, width), height: Math.max(4, height) };
  }, [cameraX, cameraY, zoom, canvasWidth, canvasHeight, worldWidth, worldHeight]);

  /**
   * Handle click/drag on minimap to navigate
   */
  const handleMinimapInteraction = useCallback(
    (clientX: number, clientY: number) => {
      if (!minimapRef.current) return;

      const rect = minimapRef.current.getBoundingClientRect();
      const minimapX = clientX - rect.left;
      const minimapY = clientY - rect.top;

      // Clamp to minimap bounds
      const clampedX = Math.max(0, Math.min(MINIMAP_WIDTH, minimapX));
      const clampedY = Math.max(0, Math.min(MINIMAP_HEIGHT, minimapY));

      // Convert to world coordinates
      const { worldX, worldY } = minimapToWorld(clampedX, clampedY, worldWidth, worldHeight);

      onNavigate(worldX, worldY);
    },
    [worldWidth, worldHeight, onNavigate]
  );

  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(true);
      handleMinimapInteraction(e.clientX, e.clientY);
    },
    [handleMinimapInteraction]
  );

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (isDragging) {
        handleMinimapInteraction(e.clientX, e.clientY);
      }
    },
    [isDragging, handleMinimapInteraction]
  );

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  // Global mouse up listener for drag release
  useEffect(() => {
    if (isDragging) {
      const handleGlobalMouseUp = () => setIsDragging(false);
      window.addEventListener('mouseup', handleGlobalMouseUp);
      return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
    }
  }, [isDragging]);

  // Render heatmap cells
  const cellWidth = MINIMAP_WIDTH / gridCols;
  const cellHeight = MINIMAP_HEIGHT / gridRows;

  return (
    <div
      style={{
        position: 'absolute',
        bottom: 16,
        right: 16,
        zIndex: 100,
      }}
    >
      {/* Toggle button when hidden */}
      {!visible && (
        <button
          onClick={onToggle}
          style={{
            background: 'white',
            border: '1px solid #ddd',
            borderRadius: 4,
            padding: '6px 10px',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            gap: 6,
            fontSize: 12,
            boxShadow: '0 1px 3px rgba(0,0,0,0.12)',
          }}
          title="Show minimap"
        >
          <Icon icon="map" size={14} />
          Minimap
        </button>
      )}

      {/* Minimap panel */}
      {visible && (
        <Card
          elevation={2}
          style={{
            padding: MINIMAP_PADDING,
            borderRadius: 6,
          }}
        >
          {/* Header with toggle */}
          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: 4,
              fontSize: 11,
              color: '#666',
            }}
          >
            <span style={{ fontWeight: 500 }}>Minimap</span>
            <button
              onClick={onToggle}
              style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                padding: 2,
                display: 'flex',
                alignItems: 'center',
                color: '#666',
              }}
              title="Hide minimap"
            >
              <Icon icon="cross" size={12} />
            </button>
          </div>

          {/* Minimap canvas */}
          <div
            ref={minimapRef}
            style={{
              width: MINIMAP_WIDTH,
              height: MINIMAP_HEIGHT,
              background: MINIMAP_BG,
              position: 'relative',
              cursor: isDragging ? 'grabbing' : 'pointer',
              borderRadius: 3,
              overflow: 'hidden',
            }}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
          >
            {/* Heatmap cells */}
            <svg
              width={MINIMAP_WIDTH}
              height={MINIMAP_HEIGHT}
              style={{ position: 'absolute', top: 0, left: 0 }}
            >
              {heatmapData.map((row, rowIndex) =>
                row.map((value, colIndex) => {
                  if (value === 0) return null;
                  const normalizedValue = value / maxDensity;
                  return (
                    <rect
                      key={`${rowIndex}-${colIndex}`}
                      x={colIndex * cellWidth}
                      y={rowIndex * cellHeight}
                      width={cellWidth}
                      height={cellHeight}
                      fill={interpolateColor(normalizedValue)}
                      opacity={0.8}
                    />
                  );
                })
              )}
            </svg>

            {/* Viewport rectangle */}
            <div
              style={{
                position: 'absolute',
                left: viewportRect.x,
                top: viewportRect.y,
                width: viewportRect.width,
                height: viewportRect.height,
                background: VIEWPORT_RECT_COLOR,
                border: `2px solid ${VIEWPORT_RECT_BORDER}`,
                borderRadius: 2,
                pointerEvents: 'none',
                boxSizing: 'border-box',
              }}
            />
          </div>

          {/* Scale indicator */}
          <div
            style={{
              marginTop: 4,
              fontSize: 10,
              color: '#999',
              textAlign: 'center',
            }}
          >
            10 years × {trainCount} trains
          </div>
        </Card>
      )}
    </div>
  );
}

