() => {
  // Check if any element with position:absolute and bottom:16 exists
  const elements = document.querySelectorAll('*');
  const minimapLike = [];
  elements.forEach(el => {
    const style = window.getComputedStyle(el);
    if (style.position === 'absolute' && style.bottom === '16px' && style.right === '16px') {
      minimapLike.push({
        tag: el.tagName,
        className: el.className,
        visible: style.display !== 'none' && style.visibility !== 'hidden',
        zIndex: style.zIndex,
        opacity: style.opacity
      });
    }
  });

  // Also check for any "Minimap" text in the page
  const minimapText = document.body.innerText.includes('Minimap') || document.body.innerText.includes('minimap');

  return { minimapLike, minimapText, bodyLength: document.body.innerText.length };
}

